{"version":3,"sources":["pages/settings/app-categories/index.uvue","pages/action/execute.uvue","App.uvue"],"sourcesContent":["<template>\r\n  <view class=\"page\">\r\n    <view class=\"page-bg\">\r\n      <image class=\"page-bg-img\" src=\"/static/images/micro-habit-page-bg.png\" mode=\"aspectFill\"></image>\r\n    </view>\r\n    <scroll-view class=\"scroll-area\" scroll-y=\"true\">\r\n      <view class=\"header-block\">\r\n        <text class=\"header-title\">App 分类管理</text>\r\n        <text class=\"header-desc\">首次见到的 App 会由系统自动归类，你可在此手动调整。已锁定的分类 LLM 不会覆盖。</text>\r\n      </view>\r\n\r\n      <view class=\"filter-row\">\r\n        <view\r\n          v-for=\"(cat, ci) in categories\"\r\n          :key=\"'cat-' + ci\"\r\n          class=\"filter-chip\"\r\n          :class=\"filterIdx === ci ? 'filter-chip-active' : ''\"\r\n          @tap=\"setFilter(ci)\">\r\n          <text class=\"filter-chip-text\">{{ cat }}</text>\r\n        </view>\r\n      </view>\r\n\r\n      <view v-if=\"visibleTags.length < 1\" class=\"empty-block\">\r\n        <text class=\"empty-text\">暂无数据</text>\r\n        <text class=\"empty-hint\">开启使用情况权限后，系统会自动记录你常用的 App</text>\r\n      </view>\r\n\r\n      <view v-else class=\"tag-list\">\r\n        <view v-for=\"(tag, ti) in visibleTags\" :key=\"'t-' + ti\" class=\"tag-card\">\r\n          <view class=\"tag-card-left\">\r\n            <text class=\"tag-label\">{{ tag.appLabel }}</text>\r\n            <text class=\"tag-pkg\">{{ tag.packageName }}</text>\r\n            <view class=\"tag-source-row\">\r\n              <text class=\"tag-source\" :class=\"getSourceClass(tag.tagSource)\">{{ getSourceText(tag.tagSource) }}</text>\r\n              <text v-if=\"tag.totalUses > 0\" class=\"tag-uses\">使用 {{ tag.totalUses }} 次</text>\r\n            </view>\r\n          </view>\r\n          <view class=\"tag-card-right\">\r\n              <picker mode=\"selector\" :range=\"categories\" :value=\"getCategoryIdx(tag.category)\" @change=\"(e: UTSJSONObject) => onCategoryChange(tag.packageName, e)\">\r\n              <view class=\"cat-picker\">\r\n                <text class=\"cat-picker-text\">{{ tag.category }}</text>\r\n                <text class=\"cat-picker-arrow\">▾</text>\r\n              </view>\r\n            </picker>\r\n            <view class=\"lock-row\" @tap=\"toggleLock(tag.packageName, !tag.isUserLocked)\">\r\n              <text class=\"lock-text\" :class=\"tag.isUserLocked ? 'lock-text-on' : ''\">{{ tag.isUserLocked ? '🔒 已锁定' : '🔓 未锁' }}</text>\r\n            </view>\r\n          </view>\r\n        </view>\r\n      </view>\r\n    </scroll-view>\r\n  </view>\r\n</template>\r\n\r\n<script setup lang=\"uts\">\r\nimport * as AppTagsDao from '../../../database/AppTagsDao'\r\nimport { AppTag, AppCategory } from '../../../models/AppTag'\r\nimport { manualSetCategory } from '../../../services/AppCategoryService'\r\n\r\nconst categories: string[] = ['social', 'video', 'game', 'work', 'study', 'reading', 'other']\r\nconst filterIdx = ref<number>(-1)\r\nconst allTags = ref<AppTag[]>([])\r\n\r\nconst visibleTags = computed<AppTag[]>(() : AppTag[] => {\r\n  const list = allTags.value\r\n  if (filterIdx.value < 0 || filterIdx.value >= categories.length) return list\r\n  const targetCat = categories[filterIdx.value] as string\r\n  const result: AppTag[] = []\r\n  for (let i = 0; i < list.length; i++) {\r\n    const t = list[i]\r\n    if (t.category == targetCat) result.push(t)\r\n  }\r\n  return result\r\n})\r\n\r\nfunction setFilter(idx: number): void {\r\n  filterIdx.value = idx\r\n}\r\n\r\nfunction getCategoryIdx(cat: string): number {\r\n  for (let i = 0; i < categories.length; i++) {\r\n    if (categories[i] == cat) return i\r\n  }\r\n  return categories.length - 1\r\n}\r\n\r\nfunction getSourceText(s: string): string {\r\n  if (s == 'llm') return 'LLM 分类'\r\n  if (s == 'user') return '手动设置'\r\n  return '待分类'\r\n}\r\n\r\nfunction getSourceClass(s: string): string {\r\n  if (s == 'llm') return 'tag-source-llm'\r\n  if (s == 'user') return 'tag-source-user'\r\n  return 'tag-source-pending'\r\n}\r\n\r\nfunction refresh(): void {\r\n  try {\r\n    allTags.value = AppTagsDao.listAll()\r\n  } catch (err) {\r\n    console.warn('[app-categories] refresh 异常: ' + JSON.stringify(err))\r\n    allTags.value = []\r\n  }\r\n}\r\n\r\nfunction onCategoryChange(pkg: string, e: UTSJSONObject): void {\r\n  try {\r\n    if (e == null) return\r\n    const detail = e['detail']\r\n    if (detail == null) return\r\n    const detailObj = detail as UTSJSONObject\r\n    if (detailObj == null) return\r\n    const val = detailObj['value']\r\n    if (typeof val !== 'number') return\r\n    const idx: number = (val as number).toInt()\r\n    if (idx < 0 || idx >= categories.length) return\r\n    const cat = categories[idx] as AppCategory\r\n    manualSetCategory(pkg, cat)\r\n    refresh()\r\n    uni.showToast({ title: '已更新', icon: 'none' })\r\n  } catch (err) {\r\n    console.warn('[app-categories] onCategoryChange 异常: ' + JSON.stringify(err))\r\n  }\r\n}\r\n\r\nfunction toggleLock(pkg: string, locked: boolean): void {\r\n  try {\r\n    AppTagsDao.setUserLocked(pkg, locked)\r\n    refresh()\r\n  } catch (err) {\r\n    console.warn('[app-categories] toggleLock 异常: ' + JSON.stringify(err))\r\n  }\r\n}\r\n\r\nonPageShow(() => {\r\n  refresh()\r\n})\r\n\r\nfunction onBack(): void {\r\n  uni.navigateBack()\r\n}\r\n</script>\r\n\r\n<style scoped>\r\n.page {\r\n  flex: 1;\r\n  background-color: transparent;\r\n  position: relative;\r\n  overflow: hidden;\r\n}\r\n.page-bg {\r\n  position: absolute;\r\n  left: 0;\r\n  top: 0;\r\n  width: 100%;\r\n  height: 100%;\r\n  z-index: 0;\r\n}\r\n.page-bg-img {\r\n  width: 100%;\r\n  height: 100%;\r\n}\r\n.scroll-area {\r\n  flex: 1;\r\n  position: relative;\r\n  z-index: 1;\r\n}\r\n.header-block {\r\n  padding: 20px 16px 12px 16px;\r\n  background-color: rgba(255, 255, 255, 0.52);\r\n  flex-direction: column;\r\n}\r\n.header-title {\r\n  font-size: 18px;\r\n  font-weight: bold;\r\n  color: #1E2A38;\r\n  margin-bottom: 6px;\r\n}\r\n.header-desc {\r\n  font-size: 12px;\r\n  color: #526273;\r\n  line-height: 1.6;\r\n}\r\n.filter-row {\r\n  flex-direction: row;\r\n  flex-wrap: wrap;\r\n  padding: 12px 12px 0 12px;\r\n  background-color: #FFFFFF;\r\n}\r\n.filter-chip {\r\n  padding: 6px 12px;\r\n  background-color: #ECF0F1;\r\n  border-radius: 14px;\r\n  margin-right: 6px;\r\n  margin-bottom: 8px;\r\n}\r\n.filter-chip-active {\r\n  background-color: #3498DB;\r\n}\r\n.filter-chip-text {\r\n  font-size: 12px;\r\n  color: #34495E;\r\n}\r\n.filter-chip-active .filter-chip-text {\r\n  color: #FFFFFF;\r\n  font-weight: bold;\r\n}\r\n.empty-block {\r\n  padding: 60px 20px;\r\n  align-items: center;\r\n}\r\n.empty-text {\r\n  font-size: 14px;\r\n  color: #7F8C8D;\r\n  margin-bottom: 6px;\r\n}\r\n.empty-hint {\r\n  font-size: 12px;\r\n  color: #95A5A6;\r\n  text-align: center;\r\n}\r\n.tag-list {\r\n  padding: 12px 12px;\r\n}\r\n.tag-card {\r\n  background-color: #FFFFFF;\r\n  border-radius: 10px;\r\n  padding: 12px;\r\n  margin-bottom: 8px;\r\n  flex-direction: row;\r\n}\r\n.tag-card-left {\r\n  flex: 1;\r\n  flex-direction: column;\r\n}\r\n.tag-card-right {\r\n  flex-direction: column;\r\n  align-items: flex-end;\r\n  margin-left: 10px;\r\n}\r\n.tag-label {\r\n  font-size: 14px;\r\n  font-weight: bold;\r\n  color: #2C3E50;\r\n  margin-bottom: 2px;\r\n}\r\n.tag-pkg {\r\n  font-size: 11px;\r\n  color: #95A5A6;\r\n  margin-bottom: 6px;\r\n}\r\n.tag-source-row {\r\n  flex-direction: row;\r\n  align-items: center;\r\n}\r\n.tag-source {\r\n  font-size: 10px;\r\n  padding: 2px 6px;\r\n  border-radius: 4px;\r\n  margin-right: 6px;\r\n}\r\n.tag-source-llm {\r\n  background-color: rgba(52, 152, 219, 0.15);\r\n  color: #3498DB;\r\n}\r\n.tag-source-user {\r\n  background-color: rgba(46, 204, 113, 0.15);\r\n  color: #27AE60;\r\n}\r\n.tag-source-pending {\r\n  background-color: rgba(243, 156, 18, 0.15);\r\n  color: #E67E22;\r\n}\r\n.tag-uses {\r\n  font-size: 10px;\r\n  color: #95A5A6;\r\n}\r\n.cat-picker {\r\n  flex-direction: row;\r\n  align-items: center;\r\n  background-color: #ECF0F1;\r\n  padding: 4px 10px;\r\n  border-radius: 6px;\r\n  margin-bottom: 4px;\r\n}\r\n.cat-picker-text {\r\n  font-size: 12px;\r\n  color: #2C3E50;\r\n  margin-right: 4px;\r\n}\r\n.cat-picker-arrow {\r\n  font-size: 10px;\r\n  color: #95A5A6;\r\n}\r\n.lock-row {\r\n  padding: 2px 0;\r\n}\r\n.lock-text {\r\n  font-size: 10px;\r\n  color: #95A5A6;\r\n}\r\n.lock-text-on {\r\n  color: #E74C3C;\r\n  font-weight: bold;\r\n}\r\n</style>\r\n",null,null],"names":[],"mappings":";;;;;;;;;;;;;;;;;;;;;;;;YA2DA,IAAM,aAAuB;gBAAC,QAAA,CAAQ;gBAAE,OAAA,CAAO;gBAAE,MAAA,CAAM;gBAAE,MAAA,CAAM;gBAAE,OAAA,CAAO;gBAAE,SAAA,CAAS;gBAAE;aAAQ,CAAA,YAA3E,MAAM;YACxB,IAAM,YAAY,IAAI,MAAM,EAAE,CAAC,CAAC;YAChC,IAAM,UAAU;YAEhB,IAAM,cAAc,2BAAmB,wBAAgB;gBACrD,IAAM,OAAO,QAAQ,KAAK;gBAC1B,IAAI,UAAU,KAAK,CAAA,CAAA,CAAG,CAAC,CAAA,EAAA,CAAI,UAAU,KAAK,CAAA,EAAA,CAAI,WAAW,MAAM;oBAAE,OAAO;;gBACxE,IAAM,YAAY,UAAU,CAAC,UAAU,KAAK,CAAC,CAAA,EAAA,CAAI,MAAM;gBACvD,IAAM,2BAAmB,KAAE;oBAC3B;oBAAK,IAAI,YAAI,CAAC;oBAAd,MAAgB,EAAC,CAAA,CAAG,KAAK,MAAM;wBAC7B,IAAM,IAAI,IAAI,CAAC,EAAE;wBACjB,IAAI,EAAE,QAAQ,CAAA,EAAA,CAAI;4BAAW,OAAO,IAAI,CAAC;;wBAFV;;;gBAIjC,OAAO;YACT;;YAEA,IAAS,iBAAU,KAAK,MAAM,GAAG,IAAI,CAAA;gBACnC,UAAU,KAAK,GAAG;YACpB;gBAFS;YAIT,IAAS,sBAAe,KAAK,MAAM,GAAG,MAAM,CAAA;oBAC1C;oBAAK,IAAI,YAAI,CAAC;oBAAd,MAAgB,EAAC,CAAA,CAAG,WAAW,MAAM;wBACnC,IAAI,UAAU,CAAC,EAAE,CAAA,EAAA,CAAI;4BAAK,OAAO;;wBADI;;;gBAGvC,OAAO,WAAW,MAAM,CAAA,CAAA,CAAG,CAAC;YAC9B;gBALS;YAOT,IAAS,qBAAc,GAAG,MAAM,GAAG,MAAM,CAAA;gBACvC,IAAI,EAAC,EAAA,CAAI;oBAAO,OAAO;;gBACvB,IAAI,EAAC,EAAA,CAAI;oBAAQ,OAAO;;gBACxB,OAAO;YACT;gBAJS;YAMT,IAAS,sBAAe,GAAG,MAAM,GAAG,MAAM,CAAA;gBACxC,IAAI,EAAC,EAAA,CAAI;oBAAO,OAAO;;gBACvB,IAAI,EAAC,EAAA,CAAI;oBAAQ,OAAO;;gBACxB,OAAO;YACT;gBAJS;YAMT,IAAS,kBAAW,IAAI,CAAA;gBACtB,IAAI;oBACF,QAAQ,KAAK,GAAG;;iBAChB,OAAO,gBAAK;oBACZ,QAAQ,IAAI,CAAC,gCAA+B,CAAA,CAAG,KAAK,SAAS,CAAC,IAAjD,CAAoD,CAAA;oBACjE,QAAQ,KAAK,GAAG,KAAE;;YAEtB;gBAPS;YAST,IAAS,wBAAiB,KAAK,MAAM,AAAX,CAAW,CAAE,GAAG,aAAa,GAAG,IAAI,CAAA;gBAC5D,IAAI;oBACF,IAAI,EAAC,EAAA,CAAI,IAAI;wBAAE;;oBACf,IAAM,SAAS,CAAC,CAAC,SAAS;oBAC1B,IAAI,OAAM,EAAA,CAAI,IAAI;wBAAE;;oBACpB,IAAM,YAAY,OAAM,EAAA,CAAI;oBAC5B,IAAI,UAAS,EAAA,CAAI,IAAI;wBAAE;;oBACvB,IAAM,OAAM,SAAS,CAAC,QAAQ;oBAC9B,IAAI,oBADE,MACQ,GAAA,CAAK;wBAAU;;oBAC7B,IAAM,KAAK,MAAM,GAAG,CAFd,KAAG,EAAG,CAEgB,MAAM,EAAE,KAAK;oBACzC,IAAI,IAAG,CAAA,CAAG,CAAC,CAAA,EAAA,CAAI,IAAG,EAAA,CAAI,WAAW,MAAM;wBAAE;;oBACzC,IAAM,MAAM,UAAU,CAAC,IAAI,CAAA,EAAA;oBAC3B,kBAAkB,GAAA,CAAG,CAAE;oBACvB;mDACgB,QAAO,OAAO,OAAM;;iBACpC,OAAO,gBAAK;oBACZ,QAAQ,IAAI,CAAC,yCAAwC,CAAA,CAAG,KAAK,SAAS,CAAC,IAA1D,CAA6D,CAAA;;YAE9E;gBAlBS;YAoBT,IAAS,kBAAW,KAAK,MAAM,AAAX,CAAW,CAAE,QAAQ,OAAO,GAAG,IAAI,CAAA;gBACrD,IAAI;oBACF,cAAyB,GAAA,CAAG,CAAE;oBAC9B;;iBACA,OAAO,gBAAK;oBACZ,QAAQ,IAAI,CAAC,mCAAkC,CAAA,CAAG,KAAK,SAAS,CAAC,IAApD,CAAuD,CAAA;;YAExE;gBAPS;YAST,WAAW,KAAK;gBACd;YACF;;YAEA,IAAS,iBAAU,IAAI,CAAA;;YAEvB;gBAFS;;;uBA3IP,IAkDO,MAAA,CAAA,CAAA,IAlDD,WAAM,OAkDL,CAlDW,CAAA;oBAChB,IAEO,MAAA,CAAA,CAAA,IAFD,WAAM,UAEL,CAFc,CAAA;wBACnB,IAAkG,OAAA,CAAA,CAAA,IAA3F,WAAM,eAAc,SAAI,0CAAyC,UAAK;sBAD/E;oBAGA,IA6Cc,aAAA,CAAA,CAAA,IA7CD,WAAM,eAAc,cAAS,OA6C5B;wBA5CZ,IAGO,MAAA,CAAA,CAAA,IAHD,WAAM,eAGL,CAHmB,CAAA;4BACxB,IAA0C,MAAA,CAAA,CAAA,IAApC,WAAM,eAA8B,CAAhB,CAAC,WAA3B,CAAmC;4BACnC,IAA6E,MAAA,CAAA,CAAA,IAAvE,WAAM,cAAiE,CAApD,CAAC;0BAF5B;wBAKA,IASO,MAAA,CAAA,CAAA,IATD,WAAM,aASL,CATiB,CAAA;4BACtB,IAOO,QAAA,CAAA,CAAA,IAAA,CAAA,CAAA,cAAA,UAAA,CANe,UAAA,CAAU,CAAA,IAAtB,GAAA,CAAG,CAAE,EAAA,CAAE,CAAP,OAAA,CAAG,CAAA,UAAA,GAAA,CAAA;uCADb,IAOO,MAAA,CAAA,CAAA,IALJ,UAAG,OAAA,CAAA,CAAW,KACf,WAAK,IAAA;oCAAC,aAAA,CAAa;oCACX,IAAA,MAAA,WAAS,GAAA,CAAK,IAAE;wCAAA;oCAAA,EAAA,IAAA,CAAA;wCAAA;oCAAA;iCAAA,GACvB,aAAG,KAAA;oCAAE,UAAU;gCAAE;iCAEb;oCADL,IAA+C,MAAA,CAAA,CAAA,IAAzC,WAAM,mBAAmC,CAAjB,CAAA,IAAI,IAAJ,CAAO,CAAA,CAAA;;;;;6BAChC;0BART;wBAWY,IAAA,MAAA,aAAY,MAAM,CAAA,CAAA,CAAA,CAAA,EAA9B;4BAAA,IAGO,MAAA,CAAA,CAAA,gBAH6B,WAAM,cAGnC;gCAFL,IAAoC,MAAA,CAAA,CAAA,IAA9B,WAAM,aAAwB,CAAZ,CAAC,OAAzB,CAA6B;gCAC7B,IAAyD,MAAA,CAAA,CAAA,IAAnD,WAAM,aAA6C,CAAjC,CAAC;;0BAG3B,KAAA;4BAAA,IAsBO,MAAA,CAAA,CAAA,gBAtBM,WAAM,WAsBZ;gCArBL,IAoBO,QAAA,CAAA,CAAA,IAAA,CAAA,CAAA,cAAA,UAAA,CApBmB,MAAA,YAAA,CAAW,CAAA,IAAvB,GAAA,CAAG,CAAE,EAAA,CAAE,CAAP,OAAA,CAAG,CAAA,UAAA,GAAA,CAAA;2CAAjB,IAoBO,MAAA,CAAA,CAAA,IApBiC,UAAG,KAAA,CAAA,CAAS,KAAI,WAAM,WAoBvD;wCAnBL,IAOO,MAAA,CAAA,CAAA,IAPD,WAAM,gBAOL,CAPoB,CAAA;4CACzB,IAAiD,MAAA,CAAA,CAAA,IAA3C,WAAM,YAAqC,CAA1B,CAAA,IAAI,IAAI,QAAQ,CAAhB,CAAgB,CAAA,CAAA,CAAvC,CAAuC;4CACvC,IAAkD,MAAA,CAAA,CAAA,IAA5C,WAAM,UAAsC,CAA7B,CAAA,IAAI,IAAI,WAAW,CAAnB,CAAmB,CAAA,CAAA,CAAxC,CAAwC;4CACxC,IAGO,MAAA,CAAA,CAAA,IAHD,WAAM,iBAGL,CAHqB,CAAA;gDAC1B,IAAyG,MAAA,CAAA,CAAA,IAAnG,WAAK,IAAA;oDAAC,YAAA,CAAY;oDAAS,eAAe,IAAI,SAAS;iDAAA,EAA4C,MAAtC,cAAc,IAAI,SAAS,GAAA,CAAA,CAAA,CAA9F,CAA8F;gDAClF,IAAA,IAAI,SAAS,CAAA,CAAA,CAAA,CAAA,EAAzB;oDAAA,IAA+E,MAAA,CAAA,CAAA,gBAAhD,WAAM,WAA0C,EAA/B,MAAG,CAAA,CAAA,IAAG,IAAI,SAAS,EAAA,CAAA,CAAG,IAAtB,CAAwB,CAAA,CAAA;gDAAA;;;;0CAL5E;wCAQA,IAUO,MAAA,CAAA,CAAA,IAVD,WAAM,iBAUL,CAVqB,CAAA;4CACxB,IAKO,iBAAA,CAAA,CAAA,IALC,UAAK,YAAY,WAAO,YAAa,WAAO,eAAe,IAAI,QAAQ,GAAI,cAAM,IAAG,GAAA;uDAAqB,iBAAiB,IAAI,WAAW,AAAf,CAAe,CAAE;;6CAK5I,+BAJP,gBAGO,GAAA;uDAAA;oDAHP,IAGO,MAAA,CAAA,CAAA,IAHD,WAAM,aAGL,CAHiB,CAAA;wDACtB,IAAuD,MAAA,CAAA,CAAA,IAAjD,WAAM,kBAA2C,CAA1B,CAAA,IAAI,IAAI,QAAQ,CAAhB,CAAgB,CAAA,CAAA,CAA7C,CAA6C;wDAC7C,IAAuC,MAAA,CAAA,CAAA,IAAjC,WAAM,mBAA2B,CAAT,CAAC;;;;;;;8CAHjC;4CAMF,IAEO,MAAA,CAAA,CAAA,IAFD,WAAM,YAAY,aAAG,KAAA;gDAAE,WAAW,IAAI,WAAW,AAAf,CAAe,CAAA,CAAG,IAAI,YAAY;4CAAA;6CAEnE;gDADL,IAA0H,MAAA,CAAA,CAAA,IAApH,WAAK,IAAA;oDAAC,WAAA,CAAW;oDAAS,IAAA,IAAI,YAAY,EAAA;wDAAA;oDAAA,EAAA,IAAA,CAAA;wDAAA;oDAAA;iDAAA,EAA0E,MAA/C,IAAA,IAAI,YAAY,EAAA;oDAAA;gDAAA,EAAA,IAAA,CAAA;oDAAA;gDAAA;gDAAA,EAAA,CAAA,CAAA;;;;;;;iCAG1F"}
