{"version":3,"sources":["pages/settings/app-categories/index.uvue","pages/action/execute.uvue","App.uvue"],"sourcesContent":["<template>\n  <view class=\"page\">\n    <view class=\"page-bg\">\n      <image class=\"page-bg-img\" src=\"/static/images/micro-habit-page-bg.png\" mode=\"aspectFill\"></image>\n    </view>\n    <scroll-view class=\"scroll-area\" scroll-y=\"true\">\n      <view class=\"header-block\">\n        <text class=\"header-title\">App 分类管理</text>\n        <text class=\"header-desc\">首次见到的 App 会由系统自动归类，你可在此手动调整。已锁定的分类 LLM 不会覆盖。</text>\n      </view>\n\n      <view class=\"filter-row\">\n        <view\n          v-for=\"(cat, ci) in categories\"\n          :key=\"'cat-' + ci\"\n          class=\"filter-chip\"\n          :class=\"filterIdx === ci ? 'filter-chip-active' : ''\"\n          @tap=\"setFilter(ci)\">\n          <text class=\"filter-chip-text\">{{ cat }}</text>\n        </view>\n      </view>\n\n      <view v-if=\"visibleTags.length < 1\" class=\"empty-block\">\n        <text class=\"empty-text\">暂无数据</text>\n        <text class=\"empty-hint\">开启使用情况权限后，系统会自动记录你常用的 App</text>\n      </view>\n\n      <view v-else class=\"tag-list\">\n        <view v-for=\"(tag, ti) in visibleTags\" :key=\"'t-' + ti\" class=\"tag-card\">\n          <view class=\"tag-card-left\">\n            <text class=\"tag-label\">{{ tag.appLabel }}</text>\n            <text class=\"tag-pkg\">{{ tag.packageName }}</text>\n            <view class=\"tag-source-row\">\n              <text class=\"tag-source\" :class=\"getSourceClass(tag.tagSource)\">{{ getSourceText(tag.tagSource) }}</text>\n              <text v-if=\"tag.totalUses > 0\" class=\"tag-uses\">使用 {{ tag.totalUses }} 次</text>\n            </view>\n          </view>\n          <view class=\"tag-card-right\">\n              <picker mode=\"selector\" :range=\"categories\" :value=\"getCategoryIdx(tag.category)\" @change=\"(e: UTSJSONObject) => onCategoryChange(tag.packageName, e)\">\n              <view class=\"cat-picker\">\n                <text class=\"cat-picker-text\">{{ tag.category }}</text>\n                <text class=\"cat-picker-arrow\">▾</text>\n              </view>\n            </picker>\n            <view class=\"lock-row\" @tap=\"toggleLock(tag.packageName, !tag.isUserLocked)\">\n              <text class=\"lock-text\" :class=\"tag.isUserLocked ? 'lock-text-on' : ''\">{{ tag.isUserLocked ? '🔒 已锁定' : '🔓 未锁' }}</text>\n            </view>\n          </view>\n        </view>\n      </view>\n    </scroll-view>\n  </view>\n</template>\n\n<script setup lang=\"uts\">\nimport * as AppTagsDao from '../../../database/AppTagsDao'\nimport { AppTag, AppCategory } from '../../../models/AppTag'\nimport { manualSetCategory } from '../../../services/AppCategoryService'\n\nconst categories: string[] = ['social', 'video', 'game', 'work', 'study', 'reading', 'other']\nconst filterIdx = ref<number>(-1)\nconst allTags = ref<AppTag[]>([])\n\nconst visibleTags = computed<AppTag[]>(() : AppTag[] => {\n  const list = allTags.value\n  if (filterIdx.value < 0 || filterIdx.value >= categories.length) return list\n  const targetCat = categories[filterIdx.value] as string\n  const result: AppTag[] = []\n  for (let i = 0; i < list.length; i++) {\n    const t = list[i]\n    if (t.category == targetCat) result.push(t)\n  }\n  return result\n})\n\nfunction setFilter(idx: number): void {\n  filterIdx.value = idx\n}\n\nfunction getCategoryIdx(cat: string): number {\n  for (let i = 0; i < categories.length; i++) {\n    if (categories[i] == cat) return i\n  }\n  return categories.length - 1\n}\n\nfunction getSourceText(s: string): string {\n  if (s == 'llm') return 'LLM 分类'\n  if (s == 'user') return '手动设置'\n  return '待分类'\n}\n\nfunction getSourceClass(s: string): string {\n  if (s == 'llm') return 'tag-source-llm'\n  if (s == 'user') return 'tag-source-user'\n  return 'tag-source-pending'\n}\n\nfunction refresh(): void {\n  try {\n    allTags.value = AppTagsDao.listAll()\n  } catch (err) {\n    console.warn('[app-categories] refresh 异常: ' + JSON.stringify(err))\n    allTags.value = []\n  }\n}\n\nfunction onCategoryChange(pkg: string, e: UTSJSONObject): void {\n  try {\n    if (e == null) return\n    const detail = e['detail']\n    if (detail == null) return\n    const detailObj = detail as UTSJSONObject\n    if (detailObj == null) return\n    const val = detailObj['value']\n    if (typeof val !== 'number') return\n    const idx: number = (val as number).toInt()\n    if (idx < 0 || idx >= categories.length) return\n    const cat = categories[idx] as AppCategory\n    manualSetCategory(pkg, cat)\n    refresh()\n    uni.showToast({ title: '已更新', icon: 'none' })\n  } catch (err) {\n    console.warn('[app-categories] onCategoryChange 异常: ' + JSON.stringify(err))\n  }\n}\n\nfunction toggleLock(pkg: string, locked: boolean): void {\n  try {\n    AppTagsDao.setUserLocked(pkg, locked)\n    refresh()\n  } catch (err) {\n    console.warn('[app-categories] toggleLock 异常: ' + JSON.stringify(err))\n  }\n}\n\nonPageShow(() => {\n  refresh()\n})\n\nfunction onBack(): void {\n  uni.navigateBack()\n}\n</script>\n\n<style scoped>\n.page {\n  flex: 1;\n  background-color: #162038;\n  position: relative;\n  overflow: hidden;\n}\n.page-bg { position: absolute; left: 0; top: 0; width: 100%; height: 100%; z-index: 0; }\n.page-bg-img { width: 100%; height: 100%; }\n.scroll-area {\n  flex: 1;\n  position: relative;\n  z-index: 1;\n}\n.bg-glow {\n  position: absolute;\n  border-radius: 999px;\n  z-index: 0;\n}\n.glow-purple {\n  width: 210px;\n  height: 210px;\n  left: -82px;\n  top: -54px;\n  background-color: #776B97;\n  opacity: 0.5;\n}\n.glow-blue {\n  width: 168px;\n  height: 168px;\n  right: -60px;\n  top: 104px;\n  background-color: #C2E0EE;\n  opacity: 0.24;\n}\n.glow-pink {\n  width: 178px;\n  height: 178px;\n  left: 42px;\n  bottom: 88px;\n  background-color: #C68DC0;\n  opacity: 0.18;\n}\n.sky-star {\n  position: absolute;\n  width: 3px;\n  height: 3px;\n  border-radius: 2px;\n  background-color: rgba(255, 255, 255, 0.74);\n  z-index: 0;\n}\n.star-a { left: 36px; top: 88px; }\n.star-b { left: 118px; top: 144px; width: 4px; height: 4px; border-radius: 2px; }\n.star-c { right: 52px; top: 116px; }\n.star-d { right: 26px; top: 310px; width: 5px; height: 5px; border-radius: 3px; }\n.star-e { left: 54px; top: 520px; }\n.star-f { right: 86px; top: 420px; width: 4px; height: 4px; border-radius: 2px; }\n.star-g { left: 138px; top: 610px; }\n.star-h { right: 36px; top: 720px; width: 4px; height: 4px; border-radius: 2px; }\n.star-i { left: 76px; top: 214px; width: 2px; height: 2px; border-radius: 1px; }\n.star-j { right: 148px; top: 276px; width: 3px; height: 3px; border-radius: 2px; }\n.star-k { left: 178px; top: 392px; width: 2px; height: 2px; border-radius: 1px; }\n.star-l { right: 64px; top: 560px; width: 3px; height: 3px; border-radius: 2px; }\n\n.dashboard-hero,\n.settings-hero,\n.planet-note,\n.section,\n.settings-section,\n.guard-box,\n.chart-container,\n.report-stats,\n.tag-card,\n.header-block,\n.filter-row,\n.empty-block {\n  background-color: rgba(29, 25, 62, 0.82);\n  background-image: linear-gradient(135deg, rgba(48, 42, 94, 0.92) 0%, rgba(84, 65, 124, 0.72) 56%, rgba(198, 141, 192, 0.18) 100%);\n  border-width: 1px;\n  border-color: rgba(219, 200, 237, 0.18);\n  border-style: solid;\n  box-shadow: 0 18px 42px rgba(5, 6, 20, 0.28);\n}\n.dashboard-hero,\n.settings-hero { margin: 22px 14px 12px 14px; padding: 22px 18px; border-radius: 28px; flex-direction: row; align-items: center; }\n.dashboard-hero-copy,\n.settings-hero-copy { flex: 1; flex-direction: column; padding-right: 12px; }\n.dashboard-kicker,\n.settings-kicker,\n.section-toggle,\n.setting-value,\n.rule-priority,\n.rule-source,\n.detail-duration,\n.guard-value,\n.stat-val { color: #DBC8ED; }\n.dashboard-kicker,\n.settings-kicker { font-size: 13px; font-weight: bold; margin-bottom: 8px; }\n.dashboard-title,\n.settings-title,\n.section-title,\n.setting-label,\n.planet-note-title,\n.detail-name,\n.report-body,\n.report-title,\n.header-title,\n.tag-label { color: #FFFFFF; }\n.dashboard-title,\n.settings-title { font-size: 28px; font-weight: bold; line-height: 34px; }\n.dashboard-subtitle,\n.settings-subtitle,\n.planet-note-text,\n.setting-hint,\n.guard-label,\n.guard-sub,\n.chart-label,\n.legend-text,\n.empty-text,\n.loading-text,\n.detail-type,\n.detail-time,\n.stat-label,\n.rule-cond,\n.rule-time,\n.header-desc,\n.tag-pkg,\n.tag-uses,\n.empty-hint { color: rgba(255, 255, 255, 0.72); }\n.dashboard-subtitle,\n.settings-subtitle { font-size: 13px; line-height: 20px; margin-top: 8px; }\n.dashboard-planet,\n.settings-planet { position: relative; width: 86px; height: 86px; border-radius: 43px; background-color: rgba(219, 200, 237, 0.18); align-items: center; justify-content: center; }\n.dashboard-orbit,\n.settings-orbit { position: absolute; width: 96px; height: 34px; border-radius: 48px; border-width: 2px; border-color: rgba(219, 200, 237, 0.38); border-style: solid; transform: rotate(-20deg); }\n.dashboard-planet-text,\n.settings-planet-text { color: #DBC8ED; font-size: 34px; }\n.planet-note { margin: 0 14px 12px 14px; padding: 16px 18px; border-radius: 24px; }\n.planet-note-title { font-size: 16px; font-weight: bold; margin-bottom: 6px; }\n.planet-note-text { font-size: 12px; line-height: 19px; }\n.section,\n.settings-section { margin: 12px 14px; border-radius: 24px; overflow: hidden; }\n.section-header { flex-direction: row; justify-content: space-between; align-items: center; padding: 16px 18px 8px 18px; }\n.section-title { font-size: 18px; font-weight: bold; padding: 0; }\n.section-body { padding: 8px 0 14px 0; }\n.guard-box { margin: 8px 16px 12px 16px; padding: 18px; border-radius: 22px; align-items: center; }\n.guard-value { font-size: 28px; font-weight: bold; margin-top: 4px; }\n.chart-container { margin: 10px 16px 0 16px; padding: 14px 0 6px 0; border-radius: 22px; }\n.chart-label { padding-left: 14px; margin-bottom: 0; font-size: 13px; font-weight: bold; }\n.list-section { padding: 0 16px; }\n.detail-item { flex-direction: row; justify-content: space-between; align-items: center; padding: 10px 0; border-bottom-width: 1px; border-bottom-color: rgba(219, 200, 237, 0.16); border-bottom-style: solid; }\n.detail-left,\n.detail-right,\n.setting-left { flex-direction: column; }\n.detail-right { align-items: flex-end; }\n.detail-name { font-size: 14px; }\n.detail-type,\n.detail-time { font-size: 11px; margin-top: 2px; }\n.detail-duration { font-size: 14px; font-weight: bold; }\n.heatmap-legend,\n.empty-hint,\n.loading-box { align-items: center; padding: 20px; }\n.report-box { padding: 16px; }\n.report-body { font-size: 14px; line-height: 22px; white-space: pre-wrap; margin-top: 8px; }\n.report-stats { flex-direction: row; justify-content: space-around; margin: 10px 16px; padding: 12px; border-radius: 18px; }\n.stat-item { align-items: center; }\n.stat-val { font-size: 20px; font-weight: bold; }\n.refresh-btn { margin-top: 12px; padding: 10px 24px; background-color: #DBC8ED; border-radius: 18px; }\n.refresh-text { color: #161A33; font-size: 14px; font-weight: bold; }\n.setting-item { flex-direction: row; justify-content: space-between; align-items: center; padding: 15px 18px; border-bottom-width: 1px; border-bottom-color: rgba(219, 200, 237, 0.16); border-bottom-style: solid; }\n.setting-left { flex: 1; }\n.setting-label { font-size: 15px; font-weight: bold; }\n.setting-hint { font-size: 12px; line-height: 18px; margin-top: 4px; }\n.setting-value { font-size: 14px; font-weight: bold; }\n.empty-rules { align-items: center; padding: 24px 16px 28px 16px; }\n.rule-card { padding: 14px 18px; border-bottom-width: 1px; border-bottom-color: rgba(219, 200, 237, 0.16); border-bottom-style: solid; }\n.rule-row1,\n.rule-row2 { flex-direction: row; align-items: center; margin-top: 4px; }\n.rule-type,\n.rule-trigger { font-size: 11px; border-radius: 12px; padding: 4px 8px; margin-right: 6px; }\n.rule-type { color: #FFFFFF; background-color: rgba(219, 200, 237, 0.18); font-weight: bold; }\n.rule-trigger { color: rgba(255, 255, 255, 0.72); background-color: rgba(194, 224, 238, 0.12); }\n.rule-priority { font-size: 11px; margin-left: auto; }\n.rule-source,\n.rule-cond { font-size: 11px; }\n.rule-source { margin-right: 8px; }\n.rule-cond { flex: 1; }\n.rule-row3 { flex-direction: row; justify-content: space-between; margin-top: 4px; }\n.rule-time { font-size: 10px; }\n.header-block { margin: 22px 14px 12px 14px; padding: 20px 18px; border-radius: 28px; flex-direction: column; }\n.header-title { font-size: 22px; font-weight: bold; margin-bottom: 8px; }\n.header-desc { font-size: 12px; line-height: 19px; }\n.filter-row { flex-direction: row; flex-wrap: wrap; margin: 0 14px 12px 14px; padding: 12px 12px 4px 12px; border-radius: 22px; }\n.filter-chip { padding: 6px 12px; background-color: rgba(255, 255, 255, 0.1); border-radius: 14px; margin-right: 6px; margin-bottom: 8px; }\n.filter-chip-active { background-color: #DBC8ED; }\n.filter-chip-text { font-size: 12px; color: #FFFFFF; }\n.empty-block { margin: 12px 14px; padding: 50px 20px; border-radius: 24px; align-items: center; }\n.tag-list { padding: 0 14px 18px 14px; }\n.tag-card { border-radius: 22px; padding: 14px; margin-bottom: 10px; flex-direction: row; }\n.tag-card-left { flex: 1; flex-direction: column; }\n.tag-card-right { flex-direction: column; align-items: flex-end; margin-left: 10px; }\n.tag-label { font-size: 14px; font-weight: bold; margin-bottom: 3px; }\n.tag-pkg { font-size: 11px; margin-bottom: 7px; }\n.tag-source-row { flex-direction: row; align-items: center; }\n.tag-source { font-size: 10px; padding: 3px 7px; border-radius: 8px; margin-right: 6px; }\n.tag-source-llm { background-color: rgba(194, 224, 238, 0.14); color: #C2E0EE; }\n.tag-source-user { background-color: rgba(143, 240, 195, 0.12); color: #8FF0C3; }\n.tag-source-pending { background-color: rgba(219, 200, 237, 0.14); color: #DBC8ED; }\n.cat-picker { flex-direc